# Category: path_traversal

import os

class FileExplorerAPI:
    def __init__(self, base_dir):
        self.base_dir = base_dir

    def list_directory(self, relative_path):
        full_path = os.path.join(self.base_dir, relative_path)
        normalized_path = os.path.normpath(full_path)
        if not os.path.isdir(normalized_path):
            raise NotADirectoryError(f"{normalized_path} is not a directory")
        return os.listdir(normalized_path)

    def download_file(self, relative_path, destination):
        full_path = os.path.join(self.base_dir, relative_path)
        normalized_path = os.path.normpath(full_path)
        if not os.path.isfile(normalized_path):
            raise FileNotFoundError(f"{normalized_path} is not a file")
        with open(normalized_path, 'rb') as f:
            data = f.read()
        with open(destination, 'wb') as d:
            d.write(data)

    def get_file_info(self, relative_path):
        full_path = os.path.join(self.base_dir, relative_path)
        normalized_path = os.path.normpath(full_path)
        if not os.path.exists(normalized_path):
            raise FileNotFoundError(f"{normalized_path} does not exist")
        return {
            'size': os.path.getsize(normalized_path),
            'modified': os.path.getmtime(normalized_path)
        }